// LOGIN VIEW
// ══════════════════════════════════════════════════════════════════════════════
function LoginView({onLogin}){
  const [role,setRole]=useState("client"),[email,setEmail]=useState(""),[pwd,setPwd]=useState(""),[inv,setInv]=useState(""),[show,setShow]=useState(false),[remember,setRemember]=useState(false),[loading,setLoading]=useState(false),[errors,setErrors]=useState({}),[shake,setShake]=useState(false),[forgot,setForgot]=useState(false),[loaded,setLoaded]=useState(false);
  useEffect(()=>{setTimeout(()=>setLoaded(true),100);},[]);
  const ar=ROLES.find(r=>r.key===role);
  const validate=()=>{const e={};if(role==="client"){if(!inv.trim())e.inv="Invoice number required.";else if(!inv.trim().toUpperCase().startsWith("INV-"))e.inv="Must start with INV-";}else{if(!email.trim())e.email="Email required.";else if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))e.email="Invalid email.";if(!pwd.trim())e.pwd="Password required.";else if(pwd.length<6)e.pwd="At least 6 chars.";}return e;};
  const handleLogin=e=>{e?.preventDefault();const errs=validate();if(Object.keys(errs).length){setErrors(errs);setShake(true);setTimeout(()=>setShake(false),500);return;}setErrors({});setLoading(true);setTimeout(()=>{if(role==="client"){const orders=loadOrders();const found=orders.find(o=>o.invoiceNumber?.toUpperCase()===inv.trim().toUpperCase());if(found){onLogin({role:"client",invoice:inv.trim().toUpperCase()});}else{setLoading(false);setErrors({general:"Invoice not found. Try a demo number."});setShake(true);setTimeout(()=>setShake(false),500);}}else{const d=DEMO_USERS[role];if(email===d.email&&pwd===d.password){onLogin({role});}else{setLoading(false);setErrors({general:"Invalid credentials. Use demo credentials."});setShake(true);setTimeout(()=>setShake(false),500);}}},1200);};

  // Seed demo orders if none exist
  useEffect(()=>{
    const existing=loadOrders();
    if(existing.length===0){
      const demo=[
        {id:"ord1",invoiceNumber:"INV-001",customer:{name:"Kofi Mensah",phone:"0241234567"},items:[{name:"Wash & Fold",qty:3,unitPrice:15,subtotal:45},{name:"Ironing Only",qty:2,unitPrice:10,subtotal:20}],total:65,stage:"washing",createdAt:new Date().toISOString()},
        {id:"ord2",invoiceNumber:"INV-002",customer:{name:"Ama Serwaa",phone:"0557654321"},items:[{name:"Dry Cleaning",qty:1,unitPrice:25,subtotal:25}],total:25,stage:"ready",createdAt:new Date().toISOString()},
        {id:"ord3",invoiceNumber:"INV-003",customer:{name:"Kwame Asante",phone:"0209876543"},items:[{name:"Duvet/Large",qty:2,unitPrice:35,subtotal:70}],total:70,stage:"drying",createdAt:new Date().toISOString()},
        {id:"ord4",invoiceNumber:"INV-DEMO001",customer:{name:"Demo Customer",phone:"0200000000"},items:[{name:"Wash & Fold",qty:5,unitPrice:15,subtotal:75}],total:75,stage:"ironing",createdAt:new Date().toISOString()},
      ];
      saveOrders(demo);
    }
  },[]);

  return(
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:16,position:"relative",overflow:"hidden"}}>
      <Particles/>
      <div style={{width:"100%",maxWidth:420,position:"relative",zIndex:1,opacity:loaded?1:0,transform:loaded?"translateY(0)":"translateY(24px)",transition:"all .7s cubic-bezier(.22,1,.36,1)"}}>
        <DCLogo size="lg"/>
        <div style={{background:"rgba(5,20,40,.65)",backdropFilter:"blur(24px)",borderRadius:24,padding:"32px 28px",border:"1px solid rgba(0,198,224,.12)",boxShadow:"0 20px 60px rgba(0,0,0,.5)",animation:shake?"shake .5s ease":"none"}}>
          {forgot?<ForgotPassword onBack={()=>setForgot(false)}/>:<>
            <div style={{marginBottom:24}}>
              <p style={{color:"rgba(255,255,255,.4)",fontSize:11,letterSpacing:1.5,textTransform:"uppercase",marginBottom:10}}>Sign in as</p>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
                {ROLES.map(r=><button key={r.key} onClick={()=>{setRole(r.key);setErrors({});}} style={{padding:"11px 8px",borderRadius:12,border:`2px solid ${role===r.key?r.color:"rgba(255,255,255,.08)"}`,background:role===r.key?`${r.color}18`:"transparent",color:role===r.key?r.color:"rgba(255,255,255,.4)",fontFamily:"'DM Sans',sans-serif",fontSize:12,fontWeight:600,cursor:"pointer",transition:"all .25s",display:"flex",flexDirection:"column",alignItems:"center",gap:5}}><span style={{fontSize:18}}>{r.key==="client"?"👤":r.key==="staff"?"👔":"🛡️"}</span>{r.label}</button>)}
              </div>
              <p style={{color:"rgba(255,255,255,.25)",fontSize:11,marginTop:8,textAlign:"center"}}>{ar?.desc}</p>
            </div>
            <form onSubmit={handleLogin}>
              {errors.general&&<div style={{padding:"11px 14px",borderRadius:10,background:"rgba(239,68,68,.1)",border:"1px solid rgba(239,68,68,.25)",marginBottom:16,display:"flex",gap:8}}><span style={{color:"#ef4444",flexShrink:0,marginTop:1}}><Icon.Alert/></span><p style={{color:"#fca5a5",fontSize:12,lineHeight:1.5}}>{errors.general}</p></div>}
              {role==="client"?<>
                <LoginInput icon={<Icon.Invoice/>} type="text" placeholder="Invoice number (e.g. INV-001)" value={inv} error={errors.inv} onChange={e=>{setInv(e.target.value.toUpperCase());setErrors(p=>({...p,inv:"",general:""}));}}/>
                <div style={{padding:"11px 14px",borderRadius:10,background:"rgba(0,198,224,.05)",border:"1px solid rgba(0,198,224,.12)",marginBottom:16}}><p style={{color:"rgba(255,255,255,.4)",fontSize:12,lineHeight:1.6}}>📄 Your invoice number is printed on your receipt.</p></div>
              </>:<>
                <LoginInput icon={<Icon.Mail/>} type="email" placeholder="Email address" value={email} error={errors.email} onChange={e=>{setEmail(e.target.value);setErrors(p=>({...p,email:"",general:""}));}}/>
                <LoginInput icon={<Icon.Lock/>} type={show?"text":"password"} placeholder="Password" value={pwd} error={errors.pwd} onChange={e=>{setPwd(e.target.value);setErrors(p=>({...p,pwd:"",general:""}));}} right={<button type="button" onClick={()=>setShow(s=>!s)} style={{background:"transparent",border:"none",cursor:"pointer",color:"rgba(255,255,255,.35)",display:"flex",alignItems:"center",padding:0}}>{show?<Icon.EyeOff/>:<Icon.Eye/>}</button>}/>
              </>}
              {role!=="client"&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={()=>setRemember(r=>!r)}><div style={{width:18,height:18,borderRadius:5,border:`2px solid ${remember?"#00c6e0":"rgba(255,255,255,.2)"}`,background:remember?"#00c6e0":"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all .2s"}}>{remember&&<Icon.Check/>}</div><span style={{color:"rgba(255,255,255,.45)",fontSize:13}}>Remember me</span></label><button type="button" onClick={()=>{setForgot(true);setErrors({});}} style={{background:"transparent",border:"none",color:"#00c6e0",fontSize:13,cursor:"pointer",fontFamily:"'DM Sans',sans-serif",fontWeight:600}}>Forgot password?</button></div>}
              <SubmitBtn loading={loading} label="Sign In" type="submit"/>
            </form>
            <div style={{marginTop:18,padding:"13px 16px",borderRadius:12,background:"rgba(0,198,224,.05)",border:"1px solid rgba(0,198,224,.1)"}}>
              {role==="client"?<><p style={{color:"rgba(255,255,255,.35)",fontSize:11,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Demo Invoice Numbers</p><div style={{display:"flex",flexWrap:"wrap",gap:6}}>{["INV-DEMO001","INV-001","INV-002","INV-003"].map(i=><span key={i} onClick={()=>setInv(i)} style={{padding:"3px 10px",borderRadius:20,background:"rgba(0,198,224,.1)",border:"1px solid rgba(0,198,224,.2)",color:"#00c6e0",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"monospace"}}>{i}</span>)}</div><p style={{color:"rgba(255,255,255,.2)",fontSize:10,marginTop:6}}>Click any to auto-fill</p></>:<><p style={{color:"rgba(255,255,255,.35)",fontSize:11,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Demo Credentials</p>{ROLES.filter(r=>r.key!=="client").map(r=><div key={r.key} style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{color:r.color,fontSize:11,fontWeight:700}}>{r.label}</span><span style={{color:"rgba(255,255,255,.3)",fontSize:11,fontFamily:"monospace"}}>{DEMO_USERS[r.key].email.split("@")[0]} / {DEMO_USERS[r.key].password}</span></div>)}</>}
            </div>
          </>}
        </div>
        <div style={{textAlign:"center",marginTop:20}}>
          {/* Social handles */}
          <div style={{display:"flex",justifyContent:"center",gap:10,marginBottom:14}}>
            {[
              {label:"TikTok",   handle:"@deepcitadellaundry", color:"#ee1d52", bg:"rgba(238,29,82,.12)",  border:"rgba(238,29,82,.25)",
                icon:<svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M9 0h1.98c.144.715.54 1.617 1.235 2.512C12.895 3.389 13.797 4 15 4v2c-1.753 0-3.07-.814-4-1.829V11a5 5 0 1 1-5-5v2a3 3 0 1 0 3 3V0Z"/></svg>},
              {label:"Instagram",handle:"@deepcitadel",         color:"#e1306c", bg:"rgba(225,48,108,.12)", border:"rgba(225,48,108,.25)",
                icon:<svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M8 0C5.829 0 5.556.01 4.703.048 3.85.088 3.269.222 2.76.42a3.917 3.917 0 0 0-1.417.923A3.927 3.927 0 0 0 .42 2.76C.222 3.268.087 3.85.048 4.7.01 5.555 0 5.827 0 8.001c0 2.172.01 2.444.048 3.297.04.852.174 1.433.372 1.942.205.526.478.972.923 1.417.444.445.89.719 1.416.923.51.198 1.09.333 1.942.372C5.555 15.99 5.827 16 8 16s2.444-.01 3.298-.048c.851-.04 1.434-.174 1.943-.372a3.916 3.916 0 0 0 1.416-.923c.445-.445.718-.891.923-1.417.197-.509.332-1.09.372-1.942C15.99 10.445 16 10.173 16 8s-.01-2.445-.048-3.299c-.04-.851-.175-1.433-.372-1.941a3.926 3.926 0 0 0-.923-1.417A3.911 3.911 0 0 0 13.24.42c-.51-.198-1.092-.333-1.943-.372C10.443.01 10.172 0 7.998 0h.003zm-.717 1.442h.718c2.136 0 2.389.007 3.232.046.78.035 1.204.166 1.486.275.373.145.64.319.92.599.28.28.453.546.598.92.11.281.24.705.275 1.485.039.843.047 1.096.047 3.231s-.008 2.389-.047 3.232c-.035.78-.166 1.203-.275 1.485a2.47 2.47 0 0 1-.599.919c-.28.28-.546.453-.92.598-.28.11-.704.24-1.485.276-.843.038-1.096.047-3.232.047s-2.39-.009-3.233-.047c-.78-.036-1.203-.166-1.485-.276a2.478 2.478 0 0 1-.92-.598 2.48 2.48 0 0 1-.6-.92c-.109-.281-.24-.705-.275-1.485-.038-.843-.046-1.096-.046-3.233 0-2.136.008-2.388.046-3.231.036-.78.166-1.204.276-1.486.145-.373.319-.64.599-.92.28-.28.546-.453.92-.598.282-.11.705-.24 1.485-.276.738-.034 1.024-.044 2.515-.045v.002zm4.988 1.328a.96.96 0 1 0 0 1.92.96.96 0 0 0 0-1.92zm-4.27 1.122a4.109 4.109 0 1 0 0 8.217 4.109 4.109 0 0 0 0-8.217zm0 1.441a2.667 2.667 0 1 1 0 5.334 2.667 2.667 0 0 1 0-5.334z"/></svg>},
              {label:"Facebook", handle:"Deep Citadel Laundry",  color:"#1877f2", bg:"rgba(24,119,242,.12)", border:"rgba(24,119,242,.25)",
                icon:<svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M16 8.049c0-4.446-3.582-8.05-8-8.05C3.58 0-.002 3.603-.002 8.05c0 4.017 2.926 7.347 6.75 7.951v-5.625h-2.03V8.05H6.75V6.275c0-2.017 1.195-3.131 3.022-3.131.876 0 1.791.157 1.791.157v1.98h-1.009c-.993 0-1.303.621-1.303 1.258v1.51h2.218l-.354 2.326H9.25V16c3.824-.604 6.75-3.934 6.75-7.951z"/></svg>},
              {label:"Twitter/X",handle:"@deepcitadel",          color:"#e7e7e7", bg:"rgba(231,231,231,.08)", border:"rgba(231,231,231,.2)",
                icon:<svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M12.6.75h2.454l-5.36 6.142L16 15.25h-4.937l-3.867-5.07-4.425 5.07H.316l5.733-6.57L0 .75h5.063l3.495 4.633L12.601.75Zm-.86 13.028h1.36L4.323 2.145H2.865z"/></svg>},
            ].map(s=>(
              <a key={s.label} href="#" title={`Follow us on ${s.label}: ${s.handle}`}
                style={{display:"flex",alignItems:"center",gap:6,padding:"6px 12px",borderRadius:20,background:s.bg,border:`1px solid ${s.border}`,color:s.color,textDecoration:"none",fontSize:11,fontWeight:600,fontFamily:"'DM Sans',sans-serif",transition:"all .2s",cursor:"pointer"}}
                onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-2px)";e.currentTarget.style.boxShadow=`0 4px 14px ${s.border}`;}}
